module RefModule(clk, reset, enable, count);input clk, reset, enable;
   output reg [2:0] count;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
   begin
      if(reset)
         count <= 3'b0;
      else if(enable)
         count <= count + 1;
   end

endmodule
